// src/pages/FarmDetail.js
import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import '../Dashboard.css';
import './FormPage.css'; // Sử dụng lại CSS cho form
import './Manager.css'; // Sử dụng lại CSS cho bảng (nếu bạn có các style bảng riêng cho activities)

function FarmDetail() {
  const { farmId } = useParams(); // Lấy farmId từ URL
  const navigate = useNavigate();
  const token = localStorage.getItem('token');
  const role = localStorage.getItem('role'); // Lấy vai trò người dùng để kiểm tra quyền

  const [farm, setFarm] = useState(null);
  const [activities, setActivities] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [message, setMessage] = useState('');

  // State cho form nhập bản ghi theo dõi
  const [activityFormData, setActivityFormData] = useState({
    speciesName: '', // Tên loài
    date: '',        // Ngày ghi nhận
    totalIndividuals: 0, // Tổng số cá thể - Sẽ được tính toán tự động
    currentStatus: {
      parents: { male: 0, female: 0 },
      otherIndividuals: { male: 0, female: 0, unidentified: 0 }
    },
    increase: {
      parents: { male: 0, female: 0 },
      otherIndividuals: { male: 0, female: 0, unidentified: 0 }
    },
    decrease: {
      parents: { male: 0, female: 0 },
      otherIndividuals: { male: 0, female: 0, unidentified: 0 }
    },
    reasonForChange: '',
    verifiedBy: '',
  });

  // Hàm fetch chi tiết cơ sở gây nuôi và các bản ghi theo dõi
  const fetchFarmDetails = async () => {
    setLoading(true);
    setError('');
    setMessage('');
    try {
      // Lấy thông tin chi tiết cơ sở nuôi
      const resFarm = await axios.get(`http://localhost:10000/api/farms/${farmId}`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      setFarm(resFarm.data);

      // Lấy các bản ghi theo dõi biến động cho cơ sở này
      const resActivities = await axios.get(`http://localhost:10000/api/farm-activities/${farmId}`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      setActivities(resActivities.data);

    } catch (err) {
      console.error('Lỗi khi tải chi tiết cơ sở nuôi hoặc các bản ghi theo dõi:', err.response?.data || err.message);
      setError(err.response?.data?.message || 'Không thể tải chi tiết cơ sở gây nuôi hoặc các bản ghi theo dõi.');
      // Chuyển hướng nếu không tìm thấy hoặc không có quyền
      if (err.response && (err.response.status === 401 || err.response.status === 403 || err.response.status === 404)) {
        navigate('/admin/farms');
      }
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (farmId && token) {
      fetchFarmDetails();
    } else if (!farmId) {
      setError('Không có ID cơ sở nuôi để xem chi tiết.');
      setLoading(false);
    } else if (!token) {
      setError('Bạn cần đăng nhập để xem chi tiết cơ sở nuôi.');
      setLoading(false);
      navigate('/');
    }
  }, [farmId, token, navigate]); // Thêm navigate vào dependency array

  const handleActivityFormChange = (e) => {
    const { name, value } = e.target;
    let newFormData = { ...activityFormData };

    // Xử lý các trường đơn giản trực tiếp
    if (['speciesName', 'date', 'reasonForChange', 'verifiedBy'].includes(name)) {
      newFormData = {
        ...newFormData,
        [name]: value,
      };
    } else {
      // Xử lý các trường nested (currentStatus, increase, decrease)
      const [mainField, subField, prop] = name.split('.');
      newFormData = {
        ...newFormData,
        [mainField]: {
          ...newFormData[mainField],
          [subField]: {
            ...newFormData[mainField][subField],
            [prop]: parseInt(value, 10) || 0,
          },
        },
      };
    }

    // Tính toán lại totalIndividuals sau mỗi thay đổi liên quan đến currentStatus
    const currentParentsMale = newFormData.currentStatus.parents.male;
    const currentParentsFemale = newFormData.currentStatus.parents.female;
    const currentOtherMale = newFormData.currentStatus.otherIndividuals.male;
    const currentOtherFemale = newFormData.currentStatus.otherIndividuals.female;
    const currentOtherUnidentified = newFormData.currentStatus.otherIndividuals.unidentified;

    newFormData.totalIndividuals =
      currentParentsMale +
      currentParentsFemale +
      currentOtherMale +
      currentOtherFemale +
      currentOtherUnidentified;

    setActivityFormData(newFormData);
  };

  const handleAddActivity = async (e) => {
    e.preventDefault();
    setMessage('');
    setError('');
    try {
      // Đảm bảo farmId được gửi cùng với dữ liệu form
      const dataToSend = {
        ...activityFormData,
        farm: farmId, // Liên kết bản ghi theo dõi với farmId
      };
      const res = await axios.post(`http://localhost:10000/api/farm-activities`, dataToSend, {
        headers: { Authorization: `Bearer ${token}` },
      });
      setMessage('Thêm bản ghi theo dõi thành công!');
      // Cập nhật lại danh sách activities
      setActivities(prevActivities => [...prevActivities, res.data]);
      // Reset form
      setActivityFormData({
        speciesName: '',
        date: '',
        totalIndividuals: 0, // Reset về 0
        currentStatus: { parents: { male: 0, female: 0 }, otherIndividuals: { male: 0, female: 0, unidentified: 0 } },
        increase: { parents: { male: 0, female: 0 }, otherIndividuals: { male: 0, female: 0, unidentified: 0 } },
        decrease: { parents: { male: 0, female: 0 }, otherIndividuals: { male: 0, female: 0, unidentified: 0 } },
        reasonForChange: '',
        verifiedBy: '',
      });
    } catch (err) {
      console.error('Lỗi khi thêm bản ghi theo dõi:', err.response?.data || err.message);
      setError(err.response?.data?.message || 'Lỗi khi thêm bản ghi theo dõi.');
    }
  };

  const handleDeleteActivity = async (activityId) => {
    if (window.confirm('Bạn có chắc chắn muốn xóa bản ghi này?')) {
      setMessage('');
      setError('');
      try {
        await axios.delete(`http://localhost:10000/api/farm-activities/${activityId}`, {
          headers: { Authorization: `Bearer ${token}` },
        });
        setMessage('Bản ghi đã được xóa thành công.');
        // Cập nhật lại danh sách activities sau khi xóa
        setActivities(prevActivities => prevActivities.filter(act => act._id !== activityId));
      } catch (err) {
        console.error('Lỗi khi xóa bản ghi theo dõi:', err.response?.data || err.message);
        setError(err.response?.data?.message || 'Lỗi khi xóa bản ghi theo dõi.');
      }
    }
  };


  if (loading) {
    return <div className="form-container"><p>Đang tải dữ liệu...</p></div>;
  }

  if (error) {
    return (
      <div className="form-container">
        <p style={{ color: 'red' }}>Lỗi: {error}</p>
        <button onClick={() => navigate('/admin/farms')}>Quay lại danh sách</button>
      </div>
    );
  }

  if (!farm) {
    return (
      <div className="form-container">
        <p style={{ color: 'orange' }}>Không tìm thấy thông tin cơ sở gây nuôi.</p>
        <button onClick={() => navigate('/admin/farms')}>Quay lại danh sách</button>
      </div>
    );
  }

  return (
    <div className="form-container">
      <h2>👁️ Sổ nuôi: {farm.tenCoSo}</h2>
      
      {/* Chỉ giữ lại Tên cơ sở và Địa chỉ */}
      <div className="detail-group">
        <strong>Tên cơ sở:</strong> <p>{farm.tenCoSo}</p>
      </div>
      <div className="detail-group">
        <strong>Địa chỉ:</strong> <p>{farm.diaChi}</p>
      </div>
      {/* Đã loại bỏ các thông tin chi tiết khác về cơ sở */}

      <h3>Danh sách loài gây nuôi hiện tại:</h3>
      {farm.species && Array.isArray(farm.species) && farm.species.length > 0 ? (
        <table className="species-table">
          <thead>
            <tr>
              <th rowSpan="2">Tên VN</th>
              <th rowSpan="2">Tên khoa học</th>
              <th colSpan="4">Tổng số cá thể nuôi</th>
              <th colSpan="2">Cá thể bố mẹ</th>
            </tr>
            <tr>
              <th>Tổng</th>
              <th>Đực</th>
              <th>Cái</th>
              <th>Không xác định</th>
              <th>Đực</th>
              <th>Cái</th>
            </tr>
          </thead>
          <tbody>
            {farm.species.map((s, idx) => {
              // Tính toán tổng số cá thể nuôi từ currentStatus của loài
              const calculatedTotalSpecies =
                (s.currentStatus?.parents?.male ?? 0) +
                (s.currentStatus?.parents?.female ?? 0) +
                (s.currentStatus?.otherIndividuals?.male ?? 0) +
                (s.currentStatus?.otherIndividuals?.female ?? 0) +
                (s.currentStatus?.otherIndividuals?.unidentified ?? 0);
              return (
                <tr key={idx}>
                  <td>{s.name}</td>
                  <td>{s.scientificName ?? 'N/A'}</td>
                  <td>{calculatedTotalSpecies}</td> {/* Hiển thị tổng đã tính */}
                  <td>{s.currentStatus?.otherIndividuals?.male ?? 0}</td>
                  <td>{s.currentStatus?.otherIndividuals?.female ?? 0}</td>
                  <td>{s.currentStatus?.otherIndividuals?.unidentified ?? 0}</td>
                  <td>{s.currentStatus?.parents?.male ?? 0}</td>
                  <td>{s.currentStatus?.parents?.female ?? 0}</td>
                </tr>
              );
            })}
          </tbody>
        </table>
      ) : (
        <p>Chưa có thông tin loài gây nuôi.</p>
      )}

      <h3>Thêm bản ghi theo dõi mới:</h3>
      {message && <div className="success-message">{message}</div>}
      {error && <div className="error-message">{error}</div>}
      <form onSubmit={handleAddActivity} className="modern-form">
        <div className="form-grid">
          <div className="form-group">
            <label>Tên loài:</label>
            <input
              type="text"
              name="speciesName"
              value={activityFormData.speciesName}
              onChange={handleActivityFormChange}
              required
            />
          </div>
          <div className="form-group">
            <label>Ngày ghi nhận:</label>
            <input
              type="date"
              name="date"
              value={activityFormData.date}
              onChange={handleActivityFormChange}
              required
            />
          </div>
          <div className="form-group">
            <label>Tổng số cá thể:</label>
            <input
              type="number"
              name="totalIndividuals"
              value={activityFormData.totalIndividuals} // Giá trị này sẽ được tính toán tự động
              onChange={handleActivityFormChange} // Vẫn cần onChange để cập nhật state
              min="0"
              readOnly // Đặt là readOnly vì nó được tính toán tự động
            />
          </div>
        </div>

        <h4>Hiện trạng nuôi:</h4>
        <div className="form-grid nested-grid">
          <div className="form-section">
            <h5>Bố mẹ:</h5>
            {/* Đã thêm div với flex để gom gọn các input */}
            <div style={{ display: 'flex', gap: '10px', flexWrap: 'wrap' }}>
              <div className="form-group">
                <label>Đực:</label>
                <input type="number" name="currentStatus.parents.male" value={activityFormData.currentStatus.parents.male} onChange={handleActivityFormChange} min="0" />
              </div>
              <div className="form-group">
                <label>Cái:</label>
                <input type="number" name="currentStatus.parents.female" value={activityFormData.currentStatus.parents.female} onChange={handleActivityFormChange} min="0" />
              </div>
            </div>
          </div>
          <div className="form-section">
            <h5>Cá thể khác:</h5>
            {/* Đã thêm div với flex để gom gọn các input */}
            <div style={{ display: 'flex', gap: '10px', flexWrap: 'wrap' }}>
              <div className="form-group">
                <label>Đực:</label>
                <input type="number" name="currentStatus.otherIndividuals.male" value={activityFormData.currentStatus.otherIndividuals.male} onChange={handleActivityFormChange} min="0" />
              </div>
              <div className="form-group">
                <label>Cái:</label>
                <input type="number" name="currentStatus.otherIndividuals.female" value={activityFormData.currentStatus.otherIndividuals.female} onChange={handleActivityFormChange} min="0" />
              </div>
              <div className="form-group">
                <label>Không rõ:</label>
                <input type="number" name="currentStatus.otherIndividuals.unidentified" value={activityFormData.currentStatus.otherIndividuals.unidentified} onChange={handleActivityFormChange} min="0" />
              </div>
            </div>
          </div>
        </div>

        <h4>Tăng đàn:</h4>
        <div className="form-grid nested-grid">
          <div className="form-section">
            <h5>Bố mẹ:</h5>
            {/* Đã thêm div với flex để gom gọn các input */}
            <div style={{ display: 'flex', gap: '10px', flexWrap: 'wrap' }}>
              <div className="form-group">
                <label>Đực:</label>
                <input type="number" name="increase.parents.male" value={activityFormData.increase.parents.male} onChange={handleActivityFormChange} min="0" />
              </div>
              <div className="form-group">
                <label>Cái:</label>
                <input type="number" name="increase.parents.female" value={activityFormData.increase.parents.female} onChange={handleActivityFormChange} min="0" />
              </div>
            </div>
          </div>
          <div className="form-section">
            <h5>Cá thể khác:</h5>
            {/* Đã thêm div với flex để gom gọn các input */}
            <div style={{ display: 'flex', gap: '10px', flexWrap: 'wrap' }}>
              <div className="form-group">
                <label>Đực:</label>
                <input type="number" name="increase.otherIndividuals.male" value={activityFormData.increase.otherIndividuals.male} onChange={handleActivityFormChange} min="0" />
              </div>
              <div className="form-group">
                <label>Cái:</label>
                <input type="number" name="increase.otherIndividuals.female" value={activityFormData.increase.otherIndividuals.female} onChange={handleActivityFormChange} min="0" />
              </div>
              <div className="form-group">
                <label>Không rõ:</label>
                <input type="number" name="increase.otherIndividuals.unidentified" value={activityFormData.increase.otherIndividuals.unidentified} onChange={handleActivityFormChange} min="0" />
              </div>
            </div>
          </div>
        </div>

        <h4>Giảm đàn:</h4>
        <div className="form-grid nested-grid">
          <div className="form-section">
            <h5>Bố mẹ:</h5>
            {/* Đã thêm div với flex để gom gọn các input */}
            <div style={{ display: 'flex', gap: '10px', flexWrap: 'wrap' }}>
              <div className="form-group">
                <label>Đực:</label>
                <input type="number" name="decrease.parents.male" value={activityFormData.decrease.parents.male} onChange={handleActivityFormChange} min="0" />
              </div>
              <div className="form-group">
                <label>Cái:</label>
                <input type="number" name="decrease.parents.female" value={activityFormData.decrease.parents.female} onChange={handleActivityFormChange} min="0" />
              </div>
            </div>
          </div>
          <div className="form-section">
            <h5>Cá thể khác:</h5>
            {/* Đã thêm div với flex để gom gọn các input */}
            <div style={{ display: 'flex', gap: '10px', flexWrap: 'wrap' }}>
              <div className="form-group">
                <label>Đực:</label>
                <input type="number" name="decrease.otherIndividuals.male" value={activityFormData.decrease.otherIndividuals.male} onChange={handleActivityFormChange} min="0" />
              </div>
              <div className="form-group">
                <label>Cái:</label>
                <input type="number" name="decrease.otherIndividuals.female" value={activityFormData.decrease.otherIndividuals.female} onChange={handleActivityFormChange} min="0" />
              </div>
              <div className="form-group">
                <label>Không rõ:</label>
                <input type="number" name="decrease.otherIndividuals.unidentified" value={activityFormData.decrease.otherIndividuals.unidentified} onChange={handleActivityFormChange} min="0" />
              </div>
            </div>
          </div>
        </div>

        <div className="form-grid">
          <div className="form-group">
            <label>Nguyên nhân biến động:</label>
            <input
              type="text"
              name="reasonForChange"
              value={activityFormData.reasonForChange}
              onChange={handleActivityFormChange}
            />
          </div>
          <div className="form-group">
            <label>Xác nhận bởi:</label>
            <input
              type="text"
              name="verifiedBy"
              value={activityFormData.verifiedBy}
              onChange={handleActivityFormChange}
            />
          </div>
        </div>
        <button type="submit" className="submit-button">Thêm bản ghi</button>
      </form>

      <h3>Lịch sử theo dõi biến động:</h3>
      <div className="activity-list-container">
        {activities.length === 0 ? (
          <p>Chưa có bản ghi theo dõi nào cho cơ sở này.</p>
        ) : (
          <table className="activity-table">
            <thead>
              <tr>
                <th rowSpan="2">TT</th>
                <th rowSpan="2">Ngày/tháng/năm</th>
                <th rowSpan="2">Tổng số cá thể</th>
                <th colSpan="5">Hiện trạng nuôi</th>
                <th colSpan="5">Tăng đàn</th>
                <th colSpan="5">Giảm đàn</th>
                <th rowSpan="2">Nguyên nhân biến động</th>
                <th rowSpan="2">Xác nhận của Cơ quan Kiểm lâm sở tại</th>
                {role === 'admin' && <th rowSpan="2">Xóa</th>}
              </tr>
              <tr>
                <th colSpan="2">Bố mẹ</th>
                <th colSpan="3">Cá thể khác</th>
                <th colSpan="2">Bố mẹ</th>
                <th colSpan="3">Cá thể khác</th>
                <th colSpan="2">Bố mẹ</th>
                <th colSpan="3">Cá thể khác</th>
              </tr>
              <tr>
                <th></th> {/* TT */}
                <th></th> {/* Ngày/tháng/năm */}
                <th></th> {/* Tổng số cá thể */}
                <th>Đực</th>
                <th>Cái</th>
                <th>Đực</th>
                <th>Cái</th>
                <th>Không rõ</th>
                <th>Đực</th>
                <th>Cái</th>
                <th>Đực</th>
                <th>Cái</th>
                <th>Không rõ</th>
                <th>Đực</th>
                <th>Cái</th>
                <th>Đực</th>
                <th>Cái</th>
                <th>Không rõ</th>
                <th></th> {/* Nguyên nhân */}
                <th></th> {/* Xác nhận */}
                {role === 'admin' && <th></th>}
              </tr>
            </thead>
            <tbody>
              {activities.map((activity, index) => {
                // Tính toán tổng số cá thể cho cột "Tổng số cá thể" trong bảng lịch sử
                const displayTotalIndividuals =
                  (activity.currentStatus?.parents?.male ?? 0) +
                  (activity.currentStatus?.parents?.female ?? 0) +
                  (activity.currentStatus?.otherIndividuals?.male ?? 0) +
                  (activity.currentStatus?.otherIndividuals?.female ?? 0) +
                  (activity.currentStatus?.otherIndividuals?.unidentified ?? 0);
                return (
                  <tr key={activity?._id || `temp-key-${Math.random()}`}>
                    <td>{index + 1}</td>
                    <td>{activity?.date ? new Date(activity.date).toLocaleDateString() : 'N/A'}</td>
                    <td>{displayTotalIndividuals}</td> {/* Hiển thị tổng đã tính */}
                    {/* Hiện trạng nuôi */}
                    <td>{activity.currentStatus?.parents?.male ?? 0}</td>
                    <td>{activity.currentStatus?.parents?.female ?? 0}</td>
                    <td>{activity.currentStatus?.otherIndividuals?.male ?? 0}</td>
                    <td>{activity.currentStatus?.otherIndividuals?.female ?? 0}</td>
                    <td>{activity.currentStatus?.otherIndividuals?.unidentified ?? 0}</td>
                    {/* Tăng đàn */}
                    <td>{activity.increase?.parents?.male ?? 0}</td>
                    <td>{activity.increase?.parents?.female ?? 0}</td>
                    <td>{activity.increase?.otherIndividuals?.male ?? 0}</td>
                    <td>{activity.increase?.otherIndividuals?.female ?? 0}</td>
                    <td>{activity.increase?.otherIndividuals?.unidentified ?? 0}</td>
                    {/* Giảm đàn */}
                    <td>{activity.decrease?.parents?.male ?? 0}</td>
                    <td>{activity.decrease?.parents?.female ?? 0}</td>
                    <td>{activity.decrease?.otherIndividuals?.male ?? 0}</td>
                    <td>{activity.decrease?.otherIndividuals?.female ?? 0}</td>
                    <td>{activity.decrease?.otherIndividuals?.unidentified ?? 0}</td>
                    <td>{activity?.reasonForChange ?? 'N/A'}</td>
                    <td>{activity?.verifiedBy ?? 'N/A'}</td>
                    {role === 'admin' && (
                      <td>
                        <button onClick={() => handleDeleteActivity(activity._id)} className="delete-button">Xóa</button>
                      </td>
                    )}
                  </tr>
                );
              })}
            </tbody>
          </table>
        )}
      </div>
      <div className="detail-actions">
        <button onClick={() => navigate('/admin/farms')} className="cancel-button">Quay lại danh sách</button>
      </div>
    </div>
  );
}

export default FarmDetail;
